import React, { useEffect, useState } from 'react'
import styled from 'styled-components'
import rick from './static/rick.png'
import {getUserChatroom} from '../WebAPI'
import {useDispatch, useSelector} from 'react-redux'
import {accountSelector} from '../redux/accountSlice'


const Message = styled.div `
border-bottom:1px solid rgba(210, 210, 210, 0.8);
border-right:1px solid rgba(210, 210, 210, 0.8);
border-left:1px solid rgba(210, 210, 210, 0.8);
display:flex;
align-items:center;
font-size:0.9rem;
padding:0 20px;
height:100px;
`

const ItemImage = styled.div `
background-image:url(${rick});
background-size:contain;
background-repeat:no-repeat;
background-position:center;
width:80px;
height:80px;
margin-right:20px;
border-radius:50%;
border:1px solid transparent;
`

const Left = styled.div `
width:30%;
display:flex;
align-items:center;
`

const Middle = styled.div `
width:40%;
`

const Right = styled.div `
width:30%;
display:flex;
flex-direction:column;
align-items:flex-end;
justify-content:center;
`
const ItemName = styled.div `
font-weight:800;
`

const SentTime = styled.div `
font-size:0.8rem;
color:grey;
`

const Sender = styled.div `
font-size:0.8rem;
`

const MessageBody = styled.div `
color:grey
`

export default function Chatroom () {
	const dispatch = useDispatch()
	const account = useSelector(accountSelector)
	const [messages, setMessages] = useState([])

	useEffect(() => {
		getUserChatroom(account.userInfo.id, setMessages)
	},[])


	return (
		<Message>
			<Left>
				<ItemImage/>
				<ItemName>Rick Owens</ItemName>
			</Left>
			<Middle>
				<MessageBody>Sure just checking</MessageBody>
			</Middle>
			<Right>
				<SentTime>less than a minute ago</SentTime>
				<Sender>Noah</Sender>
			</Right>
		</Message>
	)
}
